          <motion.span
            className="list-card-progress-fill"
            initial={false}
            animate={{ width: `${pct}%` }}
            transition={{ type: 'spring', stiffness: 220, damping: 28 }}
          />
        </span>
        <span className="list-card-progress-pct">{pct}%</span>
      </span>
    </motion.button>
  )
}

export default ListCard

