  background: white;
  color: inherit;
}

@media (prefers-color-scheme: dark) {
  .todo-list-name-input {
    background: #1f2329;
  }
}

.todo-list-actions {
  display: flex;
  gap: 0.375rem;
  flex-shrink: 0;
}

.todo-list-actions button {
  padding: 0.35rem 0.7rem;
  background: transparent;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.85rem;
  color: inherit;
  cursor: pointer;
}

.todo-list-actions button:hover {
  background: #f3f4f6;
}

@media (prefers-color-scheme: dark) {
  .todo-list-actions button {
    border-color: #2f343c;
  }
  .todo-list-actions button:hover {
    background: #262b32;
  }
}

.todo-list-actions .todo-list-delete:hover {
  background: #fee2e2;
  border-color: #fca5a5;
  color: #991b1b;
}

@media (prefers-color-scheme: dark) {
  .todo-list-actions .todo-list-delete:hover {
    background: #3f1f1f;
    border-color: #7f1d1d;
    color: #fca5a5;
  }
}

/* Add todo (item) form */

.add-todo-form {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 1rem;
}

.add-todo-form input[type='text'] {
  flex: 1;
  padding: 0.6rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.5rem;
  font-size: 1rem;
  background: white;
  color: inherit;
}

@media (prefers-color-scheme: dark) {
  .add-todo-form input[type='text'] {
    background: #1f2329;
    border-color: #2f343c;
  }
}

.add-todo-form input[type='text']:focus {
  outline: 2px solid #2563eb;
  outline-offset: 1px;
}

.add-todo-form button {
  padding: 0.6rem 1.25rem;
  background: #2563eb;
  color: white;
  border: none;
  border-radius: 0.5rem;
  font-size: 1rem;
  cursor: pointer;
}

.add-todo-form button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* Todo item rows */

.todo-rows {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.todo-row {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.6rem 0.75rem;
  border-radius: 0.5rem;
  background: white;
  border: 1px solid #e5e7eb;
}

@media (prefers-color-scheme: dark) {
  .todo-row {
    background: #1f2329;
    border-color: #2f343c;
  }
}

.todo-row-label {
  flex: 1;
  display: flex;
  align-items: center;
  gap: 0.6rem;
  cursor: pointer;
}

.todo-row.completed .todo-row-label span {
  text-decoration: line-through;
  color: #9ca3af;
}

.todo-row-delete {
  background: transparent;
  border: none;
  color: #9ca3af;
  font-size: 1.4rem;
  line-height: 1;
  cursor: pointer;
  padding: 0 0.25rem;
}

.todo-row-delete:hover {
  color: #ef4444;
}

