      { id: 11, description: 'Submit design review by Friday', isCompleted: true, todoListId: 1 },
      { id: 12, description: 'Call dentist for cleaning', isCompleted: false, todoListId: 1 },
      { id: 13, description: 'Read chapter 4 of Designing Data-Intensive Apps', isCompleted: false, todoListId: 1 },
      { id: 14, description: 'Buy birthday gift for Andrea', isCompleted: true, todoListId: 1 },
      { id: 15, description: 'Renew passport', isCompleted: false, todoListId: 1 },
    ],
    2: [
      { id: 21, description: 'Ship the auth refactor', isCompleted: true, todoListId: 2 },
      { id: 22, description: 'Review Q2 roadmap', isCompleted: false, todoListId: 2 },
