      { id: 32, description: 'The Mom Test', isCompleted: false, todoListId: 3 },
      { id: 33, description: 'Refactoring UI', isCompleted: false, todoListId: 3 },
    ],
    4: [],
  };
  const origFetch = window.fetch.bind(window);
  window.fetch = async (input, init) => {
    const url = typeof input === 'string' ? input : input.url;
    const method = init?.method ?? 'GET';
    const json = (data) => new Response(JSON.stringify(data), { headers: { 'Content-Type': 'application/json' } });
    if (url === '/api/todolists' && method === 'GET') return json(lists);
    const itemsMatch = url.match(/^\/api\/todolists\/(\d+)\/items$/);
    if (itemsMatch && method === 'GET') return json(items[+itemsMatch[1]] ?? []);
    return origFetch(input, init);
  };
  location.reload();
}

