() => {
  // Force light scheme via emulation can't be done from JS, but we can override the prefers-color-scheme inferred styles by inspecting computed values. Just probe key elements.
  const probe = (sel) => {
    const el = document.querySelector(sel);
    if (!el) return null;
    const cs = getComputedStyle(el);
    return { color: cs.color, background: cs.backgroundColor, font: cs.fontFamily };
  };
  return {
    body: probe('body'),
    title: probe('.masthead-wordmark'),
    listCard: probe('.list-card'),
    activePanel: probe('.active-panel-title'),
    todoRow: probe('.todo-row'),
  };
}

